    if n <= 2:
        return np.full(n, np.inf)

    # Compute pairwise Euclidean distances
    dist_matrix = np.zeros((n, n))
    for i in range(n):
        for j in range(i+1, n):
            d = np.sqrt(np.sum((F[i] - F[j]) ** 2))
            dist_matrix[i, j] = d
            dist_matrix[j, i] = d

    # Harmonic mean of distances to two nearest neighbours
    local_score = np.zeros(n)
    for i in range(n):
        sorted_dists = np.sort(dist_matrix[i])
        if sorted_dists[0] < 1e-12 or sorted_dists[1] < 1e-12:
            local_score[i] = 0.0
        else:
            local_score[i] = 2.0 / (1.0 / sorted_dists[0] + 1.0 / sorted_dists[1])

    # Local entropy penalty: compute normalized distance distribution entropy
    entropy = np.zeros(n)
