        if row_sum < 1e-12:
            entropy[i] = 0.0
        else:
            p = row / row_sum
            entropy[i] = -np.sum(p * np.log(p + 1e-12))

    # Rank solutions by entropy (higher entropy = more uniform spacing = less isolated)
    rank = np.argsort(np.argsort(entropy))  # 0 = lowest entropy (most isolated)
    penalty = 1.0 / (1.0 + rank)  # higher penalty for low entropy (isolated)

    diversity = local_score * penalty

    # Boundary solutions get infinite score
    for obj in range(m):
        min_val = np.min(F[:, obj])
        max_val = np.max(F[:, obj])
        for i in range(n):
            if math.isclose(F[i, obj], min_val) or math.isclose(F[i, obj], max_val):
