def crowding_distance(F: np.ndarray) -> np.ndarray:
    n, m = F.shape
    if n <= 2:
        return np.full(n, np.inf)

    # Compute reference point for hypervolume (worst values + small epsilon)
    ref = np.max(F, axis=0) + 1.0

    # Compute total hypervolume of the front
    total_hv = 1.0
    for obj in range(m):
        total_hv *= (ref[obj] - np.min(F[:, obj]))
    if total_hv < 1e-12:
        return np.full(n, np.inf)

    scores = np.zeros(n)
    for i in range(n):
        # Compute exclusive contribution of solution i
        # Remove solution i and compute hypervolume of remaining
        remaining = np.delete(F, i, axis=0)
        if len(remaining) == 0:
            scores[i] = np.inf
            continue

        # Compute hypervolume of remaining set
        hv_remaining = 1.0
        for obj in range(m):
            hv_remaining *= (ref[obj] - np.min(remaining[:, obj]))

        # Contribution = total - remaining
        contribution = total_hv - hv_remaining

        # Normalize by total hypervolume and apply log scaling
        normalized = contribution / total_hv
        if normalized > 1e-12:
            scores[i] = -math.log(normalized)
        else:
            scores[i] = 0.0

    # Handle edge solutions (first and last in each objective)
    for obj in range(m):
        idx = np.argsort(F[:, obj])
        scores[idx[0]] = np.inf
        scores[idx[-1]] = np.inf

    return scores

