def crowding_distance(F: np.ndarray) -> np.ndarray:
    n, m = F.shape
    if n <= 2:
        return np.full(n, np.inf)

    # Normalize objectives to [0,1]
    F_norm = np.zeros_like(F)
    for j in range(m):
        fmin = F[:, j].min()
        fmax = F[:, j].max()
        if fmax - fmin > 1e-10:
            F_norm[:, j] = (F[:, j] - fmin) / (fmax - fmin)

    # Compute pairwise Euclidean distances in normalized space
    dist_matrix = np.zeros((n, n))
    for i in range(n):
        for j in range(n):
            if i != j:
                dist_matrix[i, j] = np.linalg.norm(F_norm[i] - F_norm[j])

    # For each solution: harmonic mean of distances to two nearest neighbors
    score = np.zeros(n)
    for i in range(n):
        sorted_dists = np.sort(dist_matrix[i])
        if len(sorted_dists) >= 2:
            d1 = sorted_dists[0] if sorted_dists[0] > 1e-10 else 1e-10
            d2 = sorted_dists[1] if sorted_dists[1] > 1e-10 else 1e-10
            harmonic = 2.0 / (1.0/d1 + 1.0/d2)
        else:
            harmonic = 0.0

        # Local density penalty: count neighbors within radius 0.2 (in normalized space)
        radius = 0.2
        density = np.sum(dist_matrix[i] <= radius) / max(n-1, 1)
        # Weight: harmonic mean divided by (density + small constant)
        score[i] = harmonic / (density + 0.01)

    # Handle boundary solutions: assign high score
    for j in range(m):
        idx = np.argsort(F[:, j])
        score[idx[0]] = np.inf
        score[idx[-1]] = np.inf

    return score

