    # Median pairwise distance for normalization
    triu_vals = dist_matrix[np.triu_indices(n, k=1)]
    if triu_vals.size == 0:
        return np.full(n, np.inf)
    median_dist = np.median(triu_vals)
    if median_dist < 1e-12:
        return np.full(n, np.inf)

    # Radial basis function kernel sum for each point
    kernel_sum = np.zeros(n)
    for i in range(n):
        kernel_sum[i] = np.sum(np.exp(- (dist_matrix[i] / median_dist)**2))

    # Subtract mean kernel value to isolate sparse points
    mean_kernel = np.mean(kernel_sum)
    scores = kernel_sum - mean_kernel

    # Ensure boundary points (extreme in any objective) get infinite score
    for obj in range(m):
        idx_min = np.argmin(F[:, obj])
        idx_max = np.argmax(F[:, obj])
        scores[idx_min] = np.inf
        scores[idx_max] = np.inf

    return scores

