def crowding_distance(F: np.ndarray) -> np.ndarray:
    n, m = F.shape
    dist = np.zeros(n)
    for obj in range(m):
        idx = np.argsort(F[:, obj])
        f_range = F[idx[-1], obj] - F[idx[0], obj]
        if f_range < 1e-10:
            continue
        normalized = np.zeros(n)
        normalized[idx[0]] = 1.0
        normalized[idx[-1]] = 1.0
        for k in range(1, n - 1):
            diff1 = F[idx[k], obj] - F[idx[k - 1], obj]
            diff2 = F[idx[k + 1], obj] - F[idx[k], obj]
            if diff1 + diff2 < 1e-12:
                normalized[idx[k]] = 0.0
            else:
                harmonic = 2.0 / (1.0 / (diff1 + 1e-12) + 1.0 / (diff2 + 1e-12))
                normalized[idx[k]] = harmonic / f_range
        # Geometric mean across neighbors for each solution
        for i in range(n):
            # find two closest neighbors in normalized space
            vals = []
            for j in range(n):
                if i != j:
                    vals.append(abs(F[i, obj] - F[j, obj]))
            vals.sort()
            if len(vals) >= 2 and vals[0] + vals[1] > 1e-12:
                harmonic_2 = 2.0 / (1.0 / (vals[0] + 1e-12) + 1.0 / (vals[1] + 1e-12))
                dist[i] += harmonic_2 / f_range
            else:
                dist[i] += normalized[i]
    # Multiply by k-nearest sparsity factor (k=3)
    k = min(3, n - 1)
    sparsity = np.zeros(n)
    for i in range(n):
        dists = []
        for j in range(n):
            if i != j:
                d = np.sqrt(np.sum((F[i] - F[j]) ** 2))
                dists.append(d)
        dists.sort()
        if len(dists) >= k:
            sparsity[i] = np.mean(dists[:k])
        else:
            sparsity[i] = dists[0] if dists else 0.0
    # Normalize sparsity
    sp_max = np.max(sparsity)
    if sp_max > 1e-10:
        sparsity = sparsity / sp_max
    return dist * (1.0 + sparsity)
